const express = require('express');
const sgMail = require('@sendgrid/mail');

// Load SendGrid API key from environment variable
const SENDGRID_API_KEY = process.env.SENDGRID_API_KEY;

if (!SENDGRID_API_KEY) {
  throw new Error(
    'SENDGRID_API_KEY environment variable is required. ' +
    'Set it before starting the server: export SENDGRID_API_KEY=your_key_here'
  );
}

sgMail.setApiKey(SENDGRID_API_KEY);

const router = express.Router();

/**
 * POST /send-email
 * Body: {
 *   to: "recipient@example.com",
 *   subject: "Notification Subject",
 *   text: "Plain text body",
 *   html: "<p>HTML body</p>" (optional)
 * }
 */
router.post('/send-email', async (req, res) => {
  try {
    const { to, subject, text, html } = req.body;

    // Validate required fields
    if (!to || !subject || !text) {
      return res.status(400).json({
        success: false,
        error: 'Missing required fields: to, subject, and text are required.',
      });
    }

    // Validate email format (basic check)
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(to)) {
      return res.status(400).json({
        success: false,
        error: 'Invalid email address format.',
      });
    }

    const fromEmail = process.env.SENDGRID_FROM_EMAIL;
    if (!fromEmail) {
      throw new Error(
        'SENDGRID_FROM_EMAIL environment variable is required.'
      );
    }

    const msg = {
      to,
      from: fromEmail,
      subject,
      text,
      ...(html && { html }),
    };

    await sgMail.send(msg);

    // Log success without exposing sensitive details
    console.log(`Email notification sent successfully to: ${to}, subject: "${subject}"`);

    return res.status(200).json({
      success: true,
      message: 'Email sent successfully.',
    });
  } catch (error) {
    // Log error details server-side without exposing API keys or sensitive config
    console.error('Failed to send email notification:', {
      message: error.message,
      statusCode: error.code,
      // Do not log full error object as it may contain API key or request headers
    });

    const statusCode = error.code && typeof error.code === 'number' ? error.code : 500;

    return res.status(statusCode).json({
      success: false,
      error: 'Failed to send email. Check server logs for details.',
    });
  }
});

/**
 * POST /send-bulk-email
 * Body: {
 *   recipients: ["user1@example.com", "user2@example.com"],
 *   subject: "Notification Subject",
 *   text: "Plain text body",
 *   html: "<p>HTML body</p>" (optional)
 * }
 */
router.post('/send-bulk-email', async (req, res) => {
  try {
    const { recipients, subject, text, html } = req.body;

    if (!recipients || !Array.isArray(recipients) || recipients.length === 0) {
      return res.status(400).json({
        success: false,
        error: 'Missing or invalid recipients array.',
      });
    }

    if (!subject || !text) {
      return res.status(400).json({
        success: false,
        error: 'Missing required fields: subject and text are required.',
      });
    }

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    const invalidEmails = recipients.filter((email) => !emailRegex.test(email));
    if (invalidEmails.length > 0) {
      return res.status(400).json({
        success: false,
        error: `Invalid email addresses: ${invalidEmails.join(', ')}`,
      });
    }

    const fromEmail = process.env.SENDGRID_FROM_EMAIL;
    if (!fromEmail) {
      throw new Error('SENDGRID_FROM_EMAIL environment variable is required.');
    }

    const messages = recipients.map((to) => ({
      to,
      from: fromEmail,
      subject,
      text,
      ...(html && { html }),
    }));

    await sgMail.send(messages);

    console.log(
      `Bulk email sent successfully to ${recipients.length} recipients, subject: "${subject}"`
    );

    return res.status(200).json({
      success: true,
      message: `Emails sent successfully to ${recipients.length} recipients.`,
    });
  } catch (error) {
    console.error('Failed to send bulk email:', {
      message: error.message,
      statusCode: error.code,
    });

    const statusCode = error.code && typeof error.code === 'number' ? error.code : 500;

    return res.status(statusCode).json({
      success: false,
      error: 'Failed to send bulk email. Check server logs for details.',
    });
  }
});

module.exports = router;

